const payoutForDamage = (damage: Damage): number =>
  Math.floor(damage.amount - DEDUCTIBLE);

const computePayout = (claim: ClaimStep): number =>
  claim.incident.damages.reduce((sum, damage) => sum + payoutForDamage(damage), 0);

export const runScenario = (input: {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}): { results: Result[] } => {
  const policyItemsByIndex = new Map<number, Item[]>();
  let quoteCount = 0;
  const results: Result[] = input.steps.map((step, index) => {
    if (step.op === "quote") {
      policyItemsByIndex.set(index, step.items);
      const premium = quotePremium(step.items, {
        yearsWithMHPCO: input.customer.yearsWithMHPCO,
        isFollowUp: quoteCount > 0,
      });
      quoteCount++;
      return { premium };
    }
    return { payout: computePayout(step) };
  });
  return { results };
};
